-- Create table for preset templates (available to all users)
CREATE TABLE IF NOT EXISTS public.preset_templates (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    
    -- Template Info
    category TEXT NOT NULL,
    title TEXT NOT NULL,
    description TEXT NOT NULL,
    
    -- Template Structure
    general_template TEXT,
    opening_pattern TEXT,
    credibility_pattern TEXT,
    engagement_pattern TEXT,
    content_structure TEXT,
    cta_pattern TEXT,
    common_elements TEXT[],
    example_template TEXT,
    
    -- Metadata
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW(),
    is_active BOOLEAN DEFAULT TRUE,
    
    UNIQUE(category, title)
);

-- Enable RLS
ALTER TABLE public.preset_templates ENABLE ROW LEVEL SECURITY;

-- Create policy - all authenticated users can view preset templates
CREATE POLICY "All users can view preset templates"
    ON public.preset_templates
    FOR SELECT
    TO authenticated
    USING (is_active = TRUE);

-- Create index for performance
CREATE INDEX idx_preset_templates_category ON public.preset_templates(category);
CREATE INDEX idx_preset_templates_active ON public.preset_templates(is_active);

-- Create updated_at trigger
CREATE TRIGGER update_preset_templates_updated_at
    BEFORE UPDATE ON public.preset_templates
    FOR EACH ROW
    EXECUTE FUNCTION update_updated_at_column();

-- Seed preset templates
INSERT INTO public.preset_templates (category, title, description, general_template, opening_pattern, content_structure, cta_pattern, common_elements, example_template)
VALUES
    -- Experiential / Motivational Category - Template 1
    (
        'Experiential / Motivational',
        'A Story X Years In The Making',
        'Share the full story behind a major achievement. Detail your humble beginnings, the challenges you overcame, the key turning points, and the lessons learned on your long road to success. This template uses an example of a content creator''s journey.',
        '[Achievement Hook] → [Time Context] → [Origin Story] → [Initial Challenges] → [Turning Point] → [Bold Decision] → [Present Reality] → [Core Message] → [Future Vision] → [Gratitude] → [Closing Statement]',
        '[Achievement Hook - Single line, 4-7 words] State a significant milestone or achievement. Example: "2 Million subscribers on YouTube."',
        '[Time Context - Two lines] Brief statement indicating timeline with line break for emphasis. [Origin Story - 3-4 sentences, ~50 words] Starting point age/location, core commitment/promise made, personal transformation catalyst, impact statement. [Initial Challenges - 2 sentences, ~35 words] Personal transformation description and external reactions. [Turning Point - 2 sentences, ~25 words] Pivotal moment and actions taken. [Bold Decision - 2-3 sentences, ~30 words] Major life decision, others'' perception vs personal conviction, learning outcome. [Present Reality - 2-3 sentences, ~35 words] Contrast with past struggles, impact statement, value provided. [Core Message - Single line] Universal truth or personal philosophy. [Future Vision - 2 sentences, ~30 words] Next milestone and benefits. [Gratitude - Single paragraph, ~20 words] Thank you to community. [Closing Statement - 2 short lines] Forward-looking statement and memorable final phrase.',
        'Just getting started. It''s still Day 1.',
        ARRAY['Achievement milestones', 'Personal journey', 'Humble beginnings', 'Overcoming challenges', 'Transformation story', 'Inspirational closing', 'Specific numbers/metrics', 'Short paragraphs', 'Line breaks', 'Conversational tone'],
        E'2 Million subscribers on YouTube.\n\nA story 6 years in the making...\n\nStarted in a hostel room at 19... biggest change in my life.\n\nI went from an introvert... the neglect didn''t stop.\n\nLife really changed... putting myself out there.\n\nDropping out of college... valuable human skills.\n\nToday. I don''t hear... learned about AI and AI tools.\n\nYour dreams don''t need to make sense to anyone but YOU.\n\nCan''t wait to get... and govt.\n\nThank you to everyone... videos I have made.\n\nJust getting started.\nIt''s still Day 1.'
    ),
    -- Experiential / Motivational Category - Template 2
    (
        'Experiential / Motivational',
        'You Don''t Need A Big Vision To Start',
        'Tell the story of how you started with a simple goal and built momentum over time. Show how small, consistent steps led to big outcomes and how your ambition grew along with your results. This template uses a founder''s journey as an example.',
        '[Vulnerable Opening] → [Initial Reality] → [Contrasting Statements] → [Simple Truth] → [Internal Conflict] → [Moment of Doubt] → [Turning Point] → [Progress Milestones] → [Key Insight] → [Action Statement] → [Core Message] → [Universal Truth] → [Final Perspective]',
        '[Vulnerable Opening Statement - 15-20 words] Share a personal admission about your starting point, including year and business name.',
        '[Initial Reality - 15-20 words] Describe modest initial goal focusing on basic needs. [Contrasting Statements - 2 lines, 7-10 words each] State what you DIDN''T aim for using powerful aspirational terms. [Simple Truth - 15-20 words] Express basic honest intention. [Internal Conflict - 15-20 words] Describe comparison with others and self-doubt. [Moment of Doubt - 7-10 words] Express deepest fear or insecurity. [Turning Point - 15-20 words] Gradual shift in mindset. [Progress Milestones - 3 sets, 15-20 words each] Achievement and resulting expanded vision at 100, 1000, 10000 customers. [Key Insight - 10-15 words] How growth affected mindset. [Action Statement - 10-15 words] Direct advice about taking action. [Core Message - 10-15 words] Link action to outcome. [Universal Truth - 15-20 words] Challenge conventional wisdom. [Final Perspective - 3-5 words] Short powerful closing.',
        'That can come a lot later. ✌️',
        ARRAY['Vulnerable opening', 'Small beginnings', 'Progressive milestones', 'Growing ambition', 'Self-doubt to confidence', 'Ellipsis for flow', 'Short paragraphs', 'Quotation emphasis', 'Conjunction starts', 'Emoji closing'],
        E'When I started lemlist in 2018, I had 0 ambition, and I felt ashamed about it…\n\nMy only goal then was to get an OK salary so my girlfriend would stop paying the rent on her own…\n\nI didn''t want to change the world.\nI didn''t have BIG dreams to impact the lives of millions.\n\nI simply wanted to help enough people so I could build a business where I get paid.\n\nBut when I was looking at all the other "visionary" founders - it made me doubt myself…\n\nI thought that I will never succeed...\n\nBut as time went by, I started to build more and more confidence in what I was building.\n\nAnd once we reached 100 customers, I felt like reaching 1000 customers would be doable.\n\nAnd then we reached 1000 customers, so I thought that I could reach 10,000 customers...\n\nAnd then we reached 10,000 customers and felt like we could reach 100,000 customers…\n\nMy ambition grew as I built the proof that I could do it.\n\nSometimes all you have to do is put your head down and do the work.\n\nIf you can outwork your self-doubts, ambition will come along.\n\nAnd if there''s one thing I''m certain of, it''s that you don''t need to be ambitious or "visionary" to succeed...\n\nThat can come a lot later.\n\n✌️'
    ),
    -- Experiential / Motivational Category - Template 3
    (
        'Experiential / Motivational',
        'I Used to Believe X, Now I Know Y',
        'Recount your shift from a limiting belief to an empowering truth. Contrast the weakness of purely theoretical knowledge against the power of hands-on experience to achieve a goal. This template uses business as an example to frame the ''learning by doing'' mindset.',
        '[Belief Hook] → [Time Context] → [Origin Story] → [Initial Challenges] → [Turning Point] → [Bold Decision] → [Present Reality] → [Core Message] → [Future Vision] → [Gratitude] → [Closing Statement]',
        '[Belief Hook - Single line, 4-7 words] State the old limiting belief you once held.',
        '[Time Context - Two lines] Briefly indicate when and how long this belief guided you with line break for emphasis. [Origin Story - 3-4 sentences, ~50 words] Describe when/where belief started, what influenced it, how deeply you held it, hint at early consequences. [Initial Challenges - 2 sentences, ~35 words] Describe what went wrong following that belief, show disconnect between theory and results. [Turning Point - 2 sentences, ~25 words] Pivotal moment or experience that shattered old belief, highlight emotional realization. [Bold Decision - 2-3 sentences, ~30 words] Change in behavior/mindset, show courage or experimentation, reveal lesson learned. [Present Reality - 2-3 sentences, ~35 words] Show results from adopting new belief, contrast old thinking with new approach, highlight transformation. [Core Message - Single line] Powerful statement. [Future Vision - 2 sentences, ~30 words] How new belief guides future actions, ambition fueled by practicality. [Gratitude - Single paragraph, ~20 words] Thank mentors or early failures. [Closing Statement - 2 short lines] Impactful ending.',
        'Theory starts the journey. Action completes it.',
        ARRAY['Belief transformation', 'Theory vs practice', 'Learning by doing', 'Personal realization', 'Mindset shift', 'Reflective tone', 'First-person voice', 'Short paragraphs', 'Practical insight', 'Future-facing'],
        E'I used to believe hard work guaranteed success.\n\nIt shaped my decisions for years...\n\nI learned about business from case studies, not customers. I believed knowledge was enough — until real-world results proved otherwise.\n\nPlans looked perfect on paper, but nothing worked in practice. The gap between knowing and doing kept widening.\n\nOne failed launch taught me more than a year of research. I finally understood experience beats theory.\n\nI stopped reading and started testing. Every mistake became feedback, every customer, a teacher. That shift changed everything.\n\nNow I rely less on ''knowing'' and more on ''doing''. Theories guide me — experience defines me.\n\nYou don''t grow by learning. You grow by applying.\n\nCan''t wait to keep failing forward, experimenting faster, and learning directly from the real world.\n\nGrateful to everyone who let me make mistakes — and to every failed idea that taught me more than success ever did.\n\nTheory starts the journey.\nAction completes it.'
    ),
    -- Experiential / Motivational Category - Template 4
    (
        'Experiential / Motivational',
        'From ''It''s Over'' to ''It''s Just Begun''',
        'Narrate a powerful comeback story, from the brink of failure to an unexpected victory. Build tension around the lowest point, then reveal the single event that changed everything. This template uses the example of a startup securing last-minute funding.',
        '[Achievement Hook] → [Time Context] → [Origin Story] → [Initial Challenges] → [Turning Point] → [Bold Decision] → [Present Reality] → [Core Message] → [Future Vision] → [Gratitude] → [Closing Statement]',
        '[Achievement Hook - Single line, 4-7 words] Highlight the comeback theme with brevity.',
        '[Time Context - Two lines] Briefly define the moment or period of collapse with line break. [Origin Story - 3-4 sentences, ~50 words] Describe project/dream at its peak, show pride and energy before collapse, provide context for downfall. [Initial Challenges - 2 sentences, ~35 words] Show emotional and material losses, describe hopelessness or pressure. [Turning Point - 2 sentences, ~25 words] The single event or realization that sparked change, highlight emotional jolt. [Bold Decision - 2-3 sentences, ~30 words] Action taken after hope returned, show grit and urgency. [Present Reality - 2-3 sentences, ~35 words] Show today''s success/stability, contrast with collapse. [Core Message - Single line] Powerful statement. [Future Vision - 2 sentences, ~30 words] Share next chapter with renewed hope. [Gratitude - Single paragraph, ~20 words] Thank those who stayed in crisis. [Closing Statement - 2 short lines] Impactful ending.',
        'It wasn''t over. It never was.',
        ARRAY['Comeback story', 'Rock bottom moment', 'Unexpected victory', 'Emotional highs/lows', 'Tension building', 'Single turning event', 'Resilience theme', 'Hope restoration', 'Cinematic pacing', 'Authentic emotion'],
        E'From losing it all to rebuilding stronger.\n\nA story born in the ruins of failure...\n\nWe had a small team, a big dream, and a burning drive. Until one deal fell through — and it all came crashing down overnight.\n\nWe ran out of funds, options, and energy. For a while, giving up felt like the only reasonable thing to do.\n\nA single phone call changed everything — someone still believed in us when we didn''t believe in ourselves.\n\nWe went all-in again. Slept in the office. Pitched non-stop for days. That final push brought back the spark we thought was gone forever.\n\nToday, we''re profitable, grateful, and more resilient than ever. Every ''ending'' taught us how to start again — smarter and stronger.\n\nSometimes, rock bottom is the foundation of a better story.\n\nThe mission continues — to build not just a business, but belief systems that thrive under pressure.\n\nThank you to the team that refused to walk away. This story exists because of your belief, not mine.\n\nIt wasn''t over.\nIt never was.'
    ),
    -- Experiential / Motivational Category - Template 5
    (
        'Experiential / Motivational',
        'I Was Trapped, Now I''m Free',
        'Share your personal transformation story by starting with an observed conversation that mirrors your past struggles, then reveal your journey from limitation to liberation. Perfect for vulnerability-driven storytelling that inspires.',
        '[Freedom Hook] → [Time Context] → [Origin Story] → [Initial Challenges] → [Turning Point] → [Bold Decision] → [Present Reality] → [Core Message] → [Future Vision] → [Gratitude] → [Closing Statement]',
        '[Freedom Hook - Single line, 4-7 words] Express emotional contrast — trapped vs free.',
        '[Time Context - Two lines] Indicate when this emotional phase dominated your life with line break. [Origin Story - 3-4 sentences, ~50 words] Describe life before freedom, show habits/fears/environments that confined you, include internal dialogue or emotion. [Initial Challenges - 2 sentences, ~35 words] Show emotional consequences of that mindset, highlight pain and repetition. [Turning Point - 2 sentences, ~25 words] Event/question/person that triggered self-awareness, show spark of awakening. [Bold Decision - 2-3 sentences, ~30 words] Step taken toward freedom, show fear/hesitation/courage. [Present Reality - 2-3 sentences, ~35 words] Show contrast between old and new self, highlight emotional and life transformation. [Core Message - Single line] Powerful statement. [Future Vision - 2 sentences, ~30 words] How newfound freedom shapes next steps, add purpose-driven goal. [Gratitude - Single paragraph, ~20 words] Thank people/moments that guided transformation. [Closing Statement - 2 short lines] Impactful ending.',
        'No longer trapped. Finally free.',
        ARRAY['Personal transformation', 'Trapped to free', 'Emotional vulnerability', 'Self-awareness journey', 'Liberation story', 'Vivid metaphors', 'Breathing space', 'Minimal adjectives', 'Calm confidence', 'Universal themes'],
        E'I used to feel stuck in my own life.\n\nThose years taught me more than success ever did...\n\nI lived for others'' approval. Every choice I made was to fit in. Until one day, I realized I had no idea who I really was.\n\nI was overworked, uninspired, and pretending to be okay. The walls I built to protect myself became my own prison.\n\nA conversation with a stranger changed everything — they saw in me what I had forgotten existed.\n\nI started saying no. I walked away from comfort. It wasn''t easy, but every step felt like breathing for the first time.\n\nNow I live on my terms, unapologetically. I still stumble, but I no longer shrink. Freedom became my daily practice, not a dream.\n\nYou can''t find yourself in a cage you built.\n\nNow, I want to help others see the invisible walls they''ve built — and remind them there''s always a door.\n\nGrateful to those who listened when I was silent — you helped me find my voice again.\n\nNo longer trapped.\nFinally free.'
    ),
    -- Experiential / Motivational Category - Template 6
    (
        'Experiential / Motivational',
        'Why Your Good Intentions Are Hurting Others',
        'Share a personal encounter that reveals how well-meaning decisions can unexpectedly burden others. Challenge assumptions about traditional paths and explore alternative solutions that honor individual circumstances.',
        '[Provocative Hook] → [Observation Setup] → [Initial Judgment] → [Perspective Shift] → [Core Insight] → [Universal Truth] → [Challenging Question] → [Alternative Path] → [Call to Reflection]',
        '[Provocative Hook - Single line, 5-8 words] Challenge a common assumption about helping others.',
        '[Observation Setup - 2-3 sentences, ~40 words] Set the scene of a conversation or encounter that challenged your thinking. [Initial Judgment - 2 sentences, ~30 words] Describe your first reaction or conventional wisdom. [Perspective Shift - 3-4 sentences, ~50 words] Reveal the hidden burden or unintended consequence of good intentions. [Core Insight - 2 sentences, ~25 words] State the key realization about what truly helps vs what seems helpful. [Universal Truth - Single line] Powerful statement about intentions vs impact. [Challenging Question - 1-2 questions, ~20 words] Invite reader to examine their own assumptions. [Alternative Path - 2-3 sentences, ~35 words] Suggest a different approach that honors individual circumstances. [Call to Reflection - 2 short lines] Memorable closing that prompts action or thought.',
        'Good intentions aren''t enough. Understanding is.',
        ARRAY['Personal encounter', 'Challenging assumptions', 'Unintended consequences', 'Perspective shift', 'Well-meaning burden', 'Alternative solutions', 'Reflective questions', 'Individual circumstances', 'Thoughtful closing', 'Universal truth'],
        E'Sometimes helping hurts more than it heals.\n\nI met someone whose family pushed them toward success — college, career, status. All with love.\n\nI thought, "They''re lucky to have such support."\n\nBut then they said: "I feel like I''m living someone else''s dream. Every achievement feels hollow because it wasn''t mine to choose."\n\nThat hit hard. Good intentions created a cage, not a path.\n\nWhat helps isn''t always what we think helps. Sometimes the best support is stepping back.\n\nAre we listening to what people need — or projecting what we think they should want?\n\nMaybe true support means honoring their journey, even if it looks nothing like ours.\n\nGood intentions aren''t enough.\nUnderstanding is.'
    ),
    -- Case Studies Category - Template 1
    (
        'Case Studies',
        'The ''Secret Weapon'' Playbook',
        'Detail the story of a key person who turned a crisis into a major success. Break down their specific framework and principles so others can learn from their legendary comeback. This template uses the story of Apple''s Think Different campaign as an example.',
        '[Opening Hook] → [Setup Summary] → [Initial Context] → [Transition Point] → [Key Action] → [Motivation] → [Vision Statement] → [Challenge Introduction] → [Struggle Sequence] → [Turning Point Setup] → [Success Sequence] → [Lessons Learned]',
        '[Opening Hook - 1 line, 10-12 words] Start with a powerful statement about the "secret weapon" and transformation.',
        '[Setup Summary - 2 lines, 30-40 words] Provide brief context + data contrast. [Initial Context - 1 line + 3 bullet points] Describe company/person situation pre-turnaround. [Transition Point - 2 lines] Indicate the shift — re-entry of key figure or decision moment. [Key Action - 1 sentence] Specific tactical move or campaign initiated. [Motivation - 2 lines] Why this action? + underlying principle. [Vision Statement - 1-2 sentences] State the bigger dream or intent behind the strategy. [Challenge Introduction - 3 lines] Identify resistance or skepticism. [Struggle Sequence - 2 paragraphs] Detail early pushback + internal friction. [Turning Point Setup - 2 lines] Indicate the first signs of success. [Success Sequence - 3 paragraphs] Include campaign impact + measurable result. [Lessons Learned - 1 line + 3 bullet points] Summary of key principles.',
        'The ''Secret Weapon'' playbook? It''s simple: Lead with belief, not product. Build emotional equity first. Win loyalty before revenue.',
        ARRAY['Crisis to success', 'Framework breakdown', 'Legendary comeback', 'Data and quotes', 'Short paragraphs', 'Bold metrics', 'Story tension', 'Philosophy to victory', 'Key person focus', 'Credibility emphasis'],
        E'Apple''s biggest comeback wasn''t powered by tech — it was powered by mindset:\n\nIn 1997, Apple was 90 days from bankruptcy, shares under $1, and losing $1.6B annually. But one creative idea changed everything — and it wasn''t a product.\n\nHere''s how bad it was:\n• Stock price tanked below $1\n• Staff morale hit all-time low\n• Competitors dominated market share\n\nThen Jobs returned. He didn''t start with code. He started with belief.\n\nHe approved a $100M global rebrand: Think Different.\n\nHe wanted people to remember why Apple existed — not just what it sold.\n\nApple wasn''t selling computers anymore. It was selling rebellion, creativity, and identity.\n\nThe challenge: no new products, no cash flow, no faith. Could a slogan save a dying company?\n\nExecutives doubted it. Ads featuring Einstein and Gandhi felt risky, even irrelevant. But Jobs pushed forward — because great branding tells people what to believe before what to buy.\n\nThen came the launch of iMac. Suddenly, the message met the product.\n\nThe ''Think Different'' campaign became iconic — Apple''s market cap rose from $3B to $9B within 18 months. By 2001, iPod hit shelves, and the story was complete: Apple didn''t just survive — it redefined cool.\n\nThe ''Secret Weapon'' playbook? It''s simple:\n• Lead with belief, not product.\n• Build emotional equity first.\n• Win loyalty before revenue.'
    ),
    -- Case Studies Category - Template 2
    (
        'Case Studies',
        'The Underdog''s Playbook',
        'Structure the complete journey of a founder or product, from initial idea to overcoming major obstacles. Detail the early doubts, competitive threats, and controversies you faced on the way to success. This template uses the story of a tech startup that disrupted a legacy industry.',
        '[Opening Hook] → [Setup Summary] → [Origin Context] → [Early Struggles] → [Pivotal Insight] → [Strategic Move] → [Execution Details] → [Turning Point] → [Results] → [Lessons Learned]',
        '[Opening Hook - 1 line, 10-12 words] Introduce the underdog story with impact.',
        '[Setup Summary - 2 lines, 25-30 words] Brief overview of the challenge and victory. [Origin Context - 1 line + 3 bullet points] Describe what they had nothing of. [Early Struggles - 2 lines] Set up rejection & doubt. [Pivotal Insight - 2 lines] What they saw that others missed. [Strategic Move - 1 line] Their focus decision. [Execution Details - 3 bullet points] Specific tactical actions taken. [Turning Point - 1 line] Moment of momentum shift. [Results - 2 lines, 25-30 words] Measurable outcomes and success metrics. [Lessons Learned - 1 line + 3 bullet points] Core principles from the journey.',
        'The Underdog''s Playbook boils down to this: Speed beats scale. Loyalty outlasts funding. Authenticity always wins.',
        ARRAY['Founder journey', 'Overcoming obstacles', 'Early doubts', 'Competitive threats', 'Scrappy tone', 'Fast-paced', 'Data points', 'Strategic attitude', 'Challenger mindset', 'Customer obsession'],
        E'The story of how a no-name startup took on the giants — and won:\n\nIn 2013, two college dropouts launched a $5,000 prototype that terrified billion-dollar incumbents. Here''s how they did it:\n\nBack then, they had nothing:\n• No investors\n• No network\n• No brand recognition\n\nThey were laughed out of every pitch meeting — told the market was too crowded and the product too risky.\n\nBut they saw what others missed: user experience mattered more than marketing budgets.\n\nThey focused entirely on customer obsession, not investor validation.\n\nExecution:\n• Personalized onboarding for every user\n• Transparent community feedback loops\n• 24/7 founder-led support\n\nWord of mouth exploded within 90 days.\n\nRevenue grew 400% year-over-year. Within 2 years, they''d raised $50M — but on their terms.\n\nThe Underdog''s Playbook boils down to this:\n• Speed beats scale.\n• Loyalty outlasts funding.\n• Authenticity always wins.'
    ),
    -- Case Studies Category - Template 3
    (
        'Case Studies',
        'Why The Skeptics Were Wrong',
        'Prove the skeptics wrong about a growing industry. Break down how a "niche" market went mainstream by detailing consumer shifts, key players, and hard data to reveal a massive opportunity. This template uses the pet-care economy as an example.',
        '[Opening Hook] → [Setup Summary] → [Initial Context] → [Turning Point] → [Key Data] → [Challenge Introduction] → [Breakout Company] → [Strategic Levers] → [Market Validation] → [Lessons Learned]',
        '[Opening Hook - 1 line, 12-15 words] Lead with counterintuitive statement about the industry.',
        '[Setup Summary - 2 lines, 25-30 words] Overview of transformation from ignored to massive. [Initial Context - 1 line + 3 bullet points] Market state 10 years ago. [Turning Point - 2 lines] The consumer shift that changed everything. [Key Data - 3 bullet points] Growth metrics and market statistics. [Challenge Introduction - 2 lines] Who ignored it vs who seized it. [Breakout Company - 1 line] Example of major success story. [Strategic Levers - 3 bullet points] Key strategies that drove success. [Market Validation - 2 lines] How skeptics changed their minds. [Lessons Learned - 1 line + 3 bullet points] Why the conventional wisdom was wrong.',
        'Why the skeptics were wrong: Culture always drives commerce. Consumers fund what fulfills emotion. Small markets become massive when ignored long enough.',
        ARRAY['Industry growth', 'Skeptic perspective', 'Niche to mainstream', 'Consumer shifts', 'Hard data', 'Counterintuitive insight', 'Bold growth figures', 'Market validation', 'Strategic analysis', 'Concise bullets'],
        E'The $300B industry everyone thought was a joke just proved them wrong:\n\nFrom side hustle to trillion-dollar growth engine — here''s how an ignored niche transformed into one of the world''s fastest-growing consumer markets.\n\nLet''s rewind 10 years:\n• Market size: $90B globally\n• Investor interest: near zero\n• Public perception: "too emotional, not scalable"\n\nThen came the consumer shift — Millennials started spending more on pets than on themselves.\n\nKey Data:\n• 7% CAGR since 2012\n• 68% of households own pets\n• VC funding in pet-tech hit $1.2B in 2024\n\nLegacy brands ignored the shift. Startups seized it.\n\nChewy became the Amazon of pet care, growing from $0 to $10B in under a decade.\n\nStrategic Levers:\n• Subscription model for consumables\n• Emotional branding (letters from the CEO)\n• Customer-first logistics\n\nBy 2023, analysts who called it "too niche" were investing in it.\n\nWhy the skeptics were wrong:\n• Culture always drives commerce.\n• Consumers fund what fulfills emotion.\n• Small markets become massive when ignored long enough.'
    ),
    -- Case Studies Category - Template 4
    (
        'Case Studies',
        'The $1 Idea That Built a Billion-Dollar Brand',
        'Show how a small, simple idea evolved into a massive success. Trace the early inspiration, product pivot, and key execution decisions that transformed something ordinary into an empire. This template uses Dollar Shave Club as an example.',
        '[Opening Hook] → [Setup Summary] → [Origin Context] → [Pivotal Action] → [Impact Data] → [Business Model] → [Strategic Takeaways]',
        '[Opening Hook - 1 line, 10-12 words] Emphasize the irony of small idea becoming massive success.',
        '[Setup Summary - 2 lines, 25-30 words] Brief overview of viral success story. [Origin Context - 1 line + 3 bullet points] Founder''s humble starting position. [Pivotal Action - 1 line] The specific action that launched success. [Impact Data - 3 bullet points] Measurable results and exit outcomes. [Business Model - 2 lines] What they actually sold beyond the product. [Strategic Takeaways - 1 line + 3 bullet points] Core lessons from the journey.',
        'The $1 Playbook: Start small, scale fast. Humor can disrupt giants. Simplicity scales better than perfection.',
        ARRAY['Simple idea success', 'Product evolution', 'Viral growth', 'Execution decisions', 'Irony emphasis', 'Hard data', 'Witty tone', 'Confidence', 'Light humor', 'Scalability focus'],
        E'How a $1 razor became a $1 billion company:\n\nA viral video, a cheap product, and one brilliant strategy flipped an entire industry. Here''s how a joke became a business case study.\n\nIn 2011, Michael Dubin had:\n• $4,500 in savings\n• A garage office\n• A simple question: "Why are razors so expensive?"\n\nHe launched a viral video with a $4K budget.\n\nImpact:\n• 12,000 orders in 48 hours\n• $1B exit to Unilever\n• 200,000 monthly subscribers before acquisition\n\nHe didn''t sell razors. He sold convenience and confidence.\n\nThe $1 Playbook:\n• Start small, scale fast.\n• Humor can disrupt giants.\n• Simplicity scales better than perfection.'
    ),
    -- Case Studies Category - Template 5
    (
        'Case Studies',
        'How a Near-Failure Redefined an Entire Industry',
